module RAM(
    input clk,
    input rst_n,
    input write_en,
    input write_addr,
    input write_data,
    input read_en,
    input read_addr,
    output read_data
);
    parameter WIDTH = 6;
    parameter DEPTH = 8;
    reg [WIDTH-1:0] RAM [DEPTH-1:0]; 
    integer i;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            for(i=0; i<DEPTH; i=i+1) RAM[i] <= 0;
        end
        else begin
            if(write_en) RAM[write_addr] <= write_data;
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) read_data <= 0;
        else begin
            if(read_en) read_data <= RAM[read_addr];
            else read_data <= 0;
        end
    end
endmodule
